export async function GET(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  // Load saved customizations from branding.welcomeMessage (we store a JSON map there)
  // In production you'd have a proper EmailTemplate table — this is a schema-free approach
  const branding = await prisma.tenantBranding.findUnique({ where: { tenantId } })
  let saved: Record<string, any> = {}
  try {
    if (branding?.welcomeMessage) {
      const parsed = JSON.parse(branding.welcomeMessage)
      if (parsed.__emailTemplates) saved = parsed.__emailTemplates
    }
  } catch { /* use defaults */ }

  const templates = DEFAULT_TEMPLATES.map(t => ({
    ...t,
    subject: saved[t.id]?.subject ?? t.subject,
    body: saved[t.id]?.body ?? t.body,
    isCustomized: !!saved[t.id],
  }))

  return successResponse(templates)
}

export async function PATCH(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const body = await req.json()
  const { id, subject, body: templateBody } = body
  if (!id || !subject || !templateBody) return errorResponse('id, subject, and body required')

  // Load existing saved templates
  const branding = await prisma.tenantBranding.findUnique({ where: { tenantId } })
  let savedData: Record<string, any> = {}
  let existingWelcome = ''
  try {
    if (branding?.welcomeMessage) {
      const parsed = JSON.parse(branding.welcomeMessage)
      if (parsed.__emailTemplates) savedData = parsed.__emailTemplates
      // preserve actual welcome message if stored separately
    }
  } catch { /* fresh start */ }

  savedData[id] = { subject, body: templateBody, updatedAt: new Date().toISOString() }

  await prisma.tenantBranding.upsert({
    where: { tenantId },
    update: { welcomeMessage: JSON.stringify({ __emailTemplates: savedData }) },
    create: {
      tenantId,
      welcomeMessage: JSON.stringify({ __emailTemplates: savedData }),
    },
  })

  return successResponse({ id, subject, body: templateBody, isCustomized: true })
}

// Reset a template to default
export async function DELETE(req: NextRequest) {
  const { error, session } = await requireAuth(TA)
  if (error) return error
  const tenantId = getTenantId(session!)
  if (!tenantId) return errorResponse('No tenant', 400)

  const { searchParams } = new URL(req.url)
  const id = searchParams.get('id')
  if (!id) return errorResponse('id query param required')

  const branding = await prisma.tenantBranding.findUnique({ where: { tenantId } })
  let savedData: Record<string, any> = {}
  try {
    if (branding?.welcomeMessage) {
      const parsed = JSON.parse(branding.welcomeMessage)
      if (parsed.__emailTemplates) savedData = parsed.__emailTemplates
    }
  } catch { /* nothing to reset */ }

  delete savedData[id]

  await prisma.tenantBranding.upsert({
    where: { tenantId },
    update: { welcomeMessage: JSON.stringify({ __emailTemplates: savedData }) },
    create: { tenantId, welcomeMessage: JSON.stringify({ __emailTemplates: savedData }) },
  })

  return successResponse({ id, reset: true })
}
