import { getServerSession } from 'next-auth'
import { authOptions } from '@/app/api/auth/[...nextauth]/route'
import { NextResponse } from 'next/server'

// 'DEPT_ADMIN' is a virtual role — checked via session.user.isDeptAdmin flag
export async function requireAuth(allowedRoles?: string[]) {
  const session = await getServerSession(authOptions)
  if (!session?.user) return { error: NextResponse.json({ error: 'Unauthorized' }, { status: 401 }), session: null }

  const role        = (session.user as any).role       as string
  const isDeptAdmin = (session.user as any).isDeptAdmin as boolean | undefined

  if (allowedRoles) {
    const roleAllowed      = allowedRoles.filter(r => r !== 'DEPT_ADMIN').includes(role)
    const deptAdminAllowed = allowedRoles.includes('DEPT_ADMIN') && isDeptAdmin === true
    if (!roleAllowed && !deptAdminAllowed) {
      return { error: NextResponse.json({ error: 'Forbidden' }, { status: 403 }), session: null }
    }
  }

  return { error: null, session }
}

export function getTenantId(session: any): string | null {
  return session?.user?.tenantId ?? null
}

export function successResponse(data: any, status = 200) {
  return NextResponse.json({ success: true, data }, { status })
}

export function errorResponse(message: string, status = 400, code?: string) {
  return NextResponse.json({ success: false, error: message, ...(code ? { code } : {}) }, { status })
}

export function paginate(page: number, limit: number) {
  const take = Math.min(limit, 100)
  const skip = (Math.max(page, 1) - 1) * take
  return { take, skip }
}
